# Expiry tracking script — run daily via cron or CI
# Input: CSV export from your vendor register
# Output: alerts for items expiring within threshold

import csv
from datetime import date, timedelta

THRESHOLDS_DAYS = [90, 60, 30, 7]

def check_expiries(csv_path: str, today: date = None):
    today = today or date.today()
    alerts = {t: [] for t in THRESHOLDS_DAYS}

    with open(csv_path) as f:
        reader = csv.DictReader(f)
        for row in reader:
            if not row.get("expiry_date"):
                continue
            expiry = date.fromisoformat(row["expiry_date"])
            days_remaining = (expiry - today).days
            for threshold in THRESHOLDS_DAYS:
                if 0 <= days_remaining <= threshold:
                    alerts[threshold].append({
                        "vendor": row["vendor_name"],
                        "artifact": row["artifact_type"],
                        "expiry": expiry.isoformat(),
                        "days_remaining": days_remaining,
                        "owner": row.get("reviewed_by", "InfoSec team"),
                    })
                    break  # only alert at the most urgent threshold

    return alerts

# Example usage
alerts = check_expiries("vendor_register.csv")
for threshold, items in alerts.items():
    if items:
        print(f"\n--- Expiring within {threshold} days ---")
        for item in items:
            print(f"  [{item['days_remaining']}d] {item['vendor']} / {item['artifact']} "
                  f"(expires {item['expiry']}) — owner: {item['owner']}")
